class KernelMaxPool3D {
public:
    __aicore__ inline KernelMaxPool3D() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                const Ca6k04528CustomTilingData &tiling) {
        xGm_.SetGlobalBuffer((__gm__ float*)x);
        yGm_.SetGlobalBuffer((__gm__ float*)y);
        tiling_ = tiling;
    }

    __aicore__ inline void Process() {
        uint32_t total = tiling_.totalLength;
        uint32_t blockNum = GetBlockNum();
        uint32_t blockIdx = GetBlockIdx();
        uint32_t perBlock = (total + blockNum - 1) / blockNum;
        uint32_t start = blockIdx * perBlock;
        uint32_t end = (start + perBlock > total) ? total : start + perBlock;

        int32_t N = tiling_.N;
        int32_t C = tiling_.C;
        int32_t D = tiling_.D;
        int32_t H = tiling_.H;
        int32_t W = tiling_.W;
        int32_t D_out = tiling_.D_out;
        int32_t H_out = tiling_.H_out;
        int32_t W_out = tiling_.W_out;
        int32_t kernel_size = tiling_.kernel_size;
        int32_t stride = tiling_.stride;
        int32_t padding = tiling_.padding;

        for (uint32_t idx = start; idx < end; idx++) {
            uint32_t temp = idx;
            int32_t wo = temp % W_out; temp /= W_out;
            int32_t ho = temp % H_out; temp /= H_out;
            int32_t do_ = temp % D_out; temp /= D_out;
            int32_t c = temp % C; temp /= C;
            int32_t b = temp;

            int32_t di_start = do_ * stride - padding;
            int32_t hi_start = ho * stride - padding;
            int32_t wi_start = wo * stride - padding;

            float max_val = -1e38f;
            for (int32_t kd = 0; kd < kernel_size; kd++) {
                int32_t di = di_start + kd;
                if (di < 0 || di >= D) continue;
                for (int32_t kh = 0; kh < kernel_size; kh++) {
                    int32_t hi = hi_start + kh;
                    if (hi < 0 || hi >= H) continue;
                    for (int32_t kw = 0; kw < kernel_size; kw++) {
                        int32_t wi = wi_start + kw;
                        if (wi < 0 || wi >= W) continue;
                        float val = xGm_.GetValue(((b * C + c) * D + di) * H * W + hi * W + wi);
                        if (val > max_val) max_val = val;
                    }
                }
            }
            yGm_.SetValue(idx, max_val);
        }
    }

private:
    GlobalTensor<float> xGm_;
    GlobalTensor<float> yGm_;
    Ca6k04528CustomTilingData tiling_;
};

